CREATE TABLE "RERATING_TASK" ("TASKID" NUMBER(8,0), "TASKNAME" VARCHAR2(32), "TYPEID" NUMBER(6,0), "BILLCYCLE" NUMBER(8,0), "TASK_WHERE" VARCHAR2(512), "PLANTIME" DATE DEFAULT Sysdate + 1/48, "TASKCOUNT" NUMBER(3,0) DEFAULT 1, "BATCHUSER" NUMBER(3,0) DEFAULT 10, "TESTROWS" NUMBER(2,0) DEFAULT 5, "ISTEST" NUMBER(1,0) DEFAULT 0, "WHERETYPE" NUMBER(1,0) DEFAULT 0, "STATUS" NUMBER(1,0) DEFAULT 0, "UPTIME" DATE DEFAULT sysdate, "OPERATOR" VARCHAR2(32), "STATUSTIME" DATE DEFAULT sysdate) ;

