CREATE TABLE "SAFETY_STRATEGY" ("INVALID_CYCLE" NUMBER(4,0) DEFAULT 0, "PWDHIS_LIMIT" NUMBER(4,0) DEFAULT 0, "COMPOSE_LIMIT" VARCHAR2(10), "FAILCOUNT_LIMIT" NUMBER(4,0) DEFAULT 0, "PWDLEN_LIMIT" NUMBER(4,0) DEFAULT 6, "PWDLEN_MAX" NUMBER(4,0) DEFAULT 32, "PWDDUP_MAX" NUMBER(4,0) DEFAULT 3, "INVALID_LIMIT" NUMBER(4,0) DEFAULT 5, "PWDVLD_PROMPT" NUMBER(4,0) DEFAULT 7, "LOGONLOCKDUR" NUMBER(4,0) DEFAULT 30, "WAITLOCKDUR" NUMBER(4,0) DEFAULT 10, "WRONGLOCKDUR" NUMBER(4,0) DEFAULT 30, "LOGONAFTERDAYS" NUMBER(4,0) DEFAULT 90, "LAST_CALL_ET" NUMBER(5,0) DEFAULT 60, "IFCHECKUNIQUEID" NUMBER(1,0) DEFAULT 1, "ADM_PWDLEN_LIMIT" NUMBER(4,0) DEFAULT 8, "DIFCHARACTER_COUNT" NUMBER(2,0) DEFAULT 2, "RELOGONDUR" NUMBER(4,0) DEFAULT 0) ;

